1. 打开 web/src/modules/cognitive-boundary/store/cognitiveBoundarySlice.ts
2. 在 fetchAssessment asyncThunk 的 reject 条件中添加 404 错误处理
3. 当 error.status === 404 时，返回默认空评估数据 { dimensions: [] }
4. 添加错误日志记录，便于调试

pseudocode:
extraReducers: (builder) => {
  builder.addCase(fetchAssessment.rejected, (state, action) => {
    if (action.error.message?.includes('404')) {
      // 返回空评估，允许继续流程
      state.currentAssessment = { dimensions: [] }
      state.loading = false
    } else {
      state.error = action.error.message || '获取评估失败'
      state.loading = false
    }
  })
}

